INSERT INTO board_img(board_img_no, origin_name, change_name, ref_bno, img_level) SELECT SEQ_IMG_NO.NEXTVAL, c.* FROM (
SELECT #{bi.originName}, #{bi.changeName}, #{bi.refBno}, #{bi.imgLevel} FROM DUAL
) c

mapper.update:
UPDATE board
SET count = count + 1
WHERE board_no = #{boardNo}

UPDATE board
SET board_title = #{boardTitle}, board_content = #{boardContent}
WHERE board_no = #{boardNo}

UPDATE board_img
SET origin_name = #{originName}, change_name = #{changeName}
WHERE board_img_no = #{boardImgNo}

UPDATE reply
SET status = 'N'
WHERE reply_no = #{replyNo} AND reply_writer = #{replyWriter}
